// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721Enumerable.sol";
import "@openzeppelin/contracts/utils/cryptography/MerkleProof.sol";

contract MyNFTToken is ERC721Enumerable, ReentrancyGuard, Ownable {
    using Strings for uint256;

    uint256 public PRICE;
    uint256 public MAX_PER_TXN;
    uint256 public maxSupply;
    uint256 public freeMaxSupply;
    string private _baseTokenURI;

    bool public publicSale;
    bytes32 private merkleRoot;

    event PublicSaleToggled(bool status);
    event Minted(address indexed sender, uint256 amount);

    constructor(
        string memory name,
        string memory symbol,
        string memory baseTokenURI,
        uint256 price,
        uint256 maxPerTxn,
        uint256 maxSupply_,
        uint256 freeMaxSupply_,
        bytes32 initialMerkleRoot
    ) ERC721(name, symbol) {
        _baseTokenURI = baseTokenURI;
        PRICE = price;
        MAX_PER_TXN = maxPerTxn;
        maxSupply = maxSupply_;
        freeMaxSupply = freeMaxSupply_;
        publicSale = false;
        merkleRoot = initialMerkleRoot;
    }

    modifier onlyOwner() {
        require(msg.sender == owner(), "Not owner");
        _;
    }

    function togglePublicSale() external onlyOwner {
        publicSale = !publicSale;
        emit PublicSaleToggled(publicSale);
    }

    function mint(uint256 quantity, bytes32[] calldata proof) external payable nonReentrant {
        require(publicSale || msg.sender == owner(), "Sale closed");
        require(quantity > 0 && quantity <= MAX_PER_TXN, "Invalid quantity");
        require(totalSupply() + quantity <= maxSupply, "Exceeds max supply");

        if (proof.length > 0) {
            bytes32 leaf = keccak256(abi.encodePacked(msg.sender, quantity));
            require(MerkleProof.verify(proof, merkleRoot, leaf), "Invalid proof");
        }

        uint256 totalCost = quantity * PRICE;
        require(msg.value >= totalCost, "Insufficient funds");

        _safeMint(msg.sender, quantity);
        emit Minted(msg.sender, quantity);
    }

    function adminMint(address to, uint256 quantity) external onlyOwner {
        require(totalSupply() + quantity <= maxSupply, "Exceeds max supply");
        require(quantity > 0, "Invalid quantity");

        _safeMint(to, quantity);
        emit Minted(to, quantity);
    }

    function decreaseTotalSupply(uint256 quantity) external onlyOwner {
        require(quantity > 0 && quantity <= totalSupply(), "Invalid quantity");
        _burn(tokenOfOwnerByIndex(owner(), 0), quantity);
    }

    function setBaseURI(string calldata baseURI) external onlyOwner {
        _baseTokenURI = baseURI;
    }

    function _baseURI() internal view override returns (string memory) {
        return _baseTokenURI;
    }

    function setMerkleRoot(bytes32 newMerkleRoot) external onlyOwner {
        merkleRoot = newMerkleRoot;
    }

    function _beforeTokenTransfer(
        address from,
        address to,
        uint256 tokenId
    ) internal override(ERC721Enumerable) {
        super._beforeTokenTransfer(from, to, tokenId);
    }

    function _burn(uint256 tokenId) internal override(ERC721) {
        super._burn(tokenId);
        // Additional logic if needed, e.g., updating supply or other state variables
    }

    receive() external payable {}
}
